import apiClient from './apiClient';

function buildParams(params = {}) {
  const cleaned = {};
  Object.entries(params).forEach(([key, value]) => {
    if (value === undefined || value === null || value === '') return;
    cleaned[key] = value;
  });
  return cleaned;
}

export async function listResource(path, params = {}) {
  const response = await apiClient.get(path, { params: buildParams(params) });
  return response.data;
}

export async function getResource(path, id) {
  const response = await apiClient.get(`${path}${id}/`);
  return response.data;
}

export async function createResource(path, payload) {
  const response = await apiClient.post(path, payload);
  return response.data;
}

export async function updateResource(path, id, payload) {
  const response = await apiClient.put(`${path}${id}/`, payload);
  return response.data;
}

export async function patchResource(path, id, payload) {
  const response = await apiClient.patch(`${path}${id}/`, payload);
  return response.data;
}

export async function deleteResource(path, id) {
  await apiClient.delete(`${path}${id}/`);
}

