import PropTypes from 'prop-types';
import { useMemo, useState } from 'react';

import Button from '@mui/material/Button';
import Dialog from '@mui/material/Dialog';
import DialogActions from '@mui/material/DialogActions';
import DialogContent from '@mui/material/DialogContent';
import DialogTitle from '@mui/material/DialogTitle';
import Typography from '@mui/material/Typography';

import useToast from 'app/providers/useToast';
import useAuth from 'features/auth/useAuth';
import { hasRoleAtLeast } from 'features/auth/roles';
import extractApiErrorMessage from 'utils/apiError';
import { createResource, deleteResource, patchResource } from 'lib/http/resourceClient';

import usePaginatedResource from '../usePaginatedResource';
import ResourceFormDialog from './ResourceFormDialog';
import ResourceTableCard from './ResourceTableCard';

export default function CrudResourceModule({
  title,
  path,
  columns,
  fields,
  defaultOrdering = '',
  extraFilters = [],
  mapPayload,
  onView,
  searchPlaceholder = 'Buscar...',
  canCreate = null,
  canEdit = null,
  canDelete = null
}) {
  const { showToast } = useToast();
  const { user } = useAuth();
  const [modalOpen, setModalOpen] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [filterValues, setFilterValues] = useState({});

  const { items, loading, error, pagination, params, setParams, refetch } = usePaginatedResource(path, {
    ordering: defaultOrdering
  });

  const resolvedFields = useMemo(() => (typeof fields === 'function' ? fields() : fields), [fields]);
  const resolvedCanCreate = canCreate ?? hasRoleAtLeast(user?.role, 'OPERADOR');
  const resolvedCanEdit = canEdit ?? hasRoleAtLeast(user?.role, 'OPERADOR');
  const resolvedCanDelete = canDelete ?? hasRoleAtLeast(user?.role, 'ADMINISTRADOR');

  const closeModal = () => {
    setModalOpen(false);
    setSelectedItem(null);
  };

  const openCreate = () => {
    setSelectedItem(null);
    setModalOpen(true);
  };

  const openEdit = (item) => {
    setSelectedItem(item);
    setModalOpen(true);
  };

  const handleSubmit = async (values, formikHelpers) => {
    try {
      const payload = mapPayload ? mapPayload(values, selectedItem) : values;
      if (selectedItem) {
        await patchResource(path, selectedItem.id, payload);
        showToast('Registro actualizado correctamente.', 'success');
      } else {
        await createResource(path, payload);
        showToast('Registro creado correctamente.', 'success');
      }
      closeModal();
      refetch();
    } catch (err) {
      showToast(extractApiErrorMessage(err, 'No se pudo guardar el registro.'), 'error');
    } finally {
      formikHelpers.setSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!deleteTarget) return;
    try {
      await deleteResource(path, deleteTarget.id);
      showToast('Registro eliminado.', 'success');
      setDeleteTarget(null);
      refetch();
    } catch (err) {
      showToast(extractApiErrorMessage(err, 'No se pudo eliminar el registro.'), 'error');
    }
  };

  const handleSearchChange = (value) => {
    setParams((prev) => ({ ...prev, page: 1, search: value }));
  };

  const handleFilterChange = (key, value) => {
    setFilterValues((prev) => ({ ...prev, [key]: value }));
    setParams((prev) => ({ ...prev, page: 1, [key]: value }));
  };

  const rows = useMemo(() => items, [items]);

  return (
    <>
      <ResourceTableCard
        title={title}
        rows={rows}
        columns={columns}
        loading={loading}
        error={error}
        searchValue={params.search || ''}
        searchPlaceholder={searchPlaceholder}
        onSearchChange={handleSearchChange}
        onCreate={resolvedCanCreate ? openCreate : null}
        onEdit={resolvedCanEdit ? openEdit : null}
        onDelete={resolvedCanDelete ? setDeleteTarget : null}
        onView={onView}
        pagination={pagination}
        onPageChange={(page) => setParams((prev) => ({ ...prev, page }))}
        extraFilters={extraFilters}
        filters={filterValues}
        onFilterChange={handleFilterChange}
      />

      {resolvedCanCreate || resolvedCanEdit ? (
        <ResourceFormDialog
          open={modalOpen}
          title={selectedItem ? `Editar ${title}` : `Nuevo ${title}`}
          fields={resolvedFields}
          initialData={selectedItem}
          onClose={closeModal}
          onSubmit={handleSubmit}
        />
      ) : null}

      <Dialog open={Boolean(deleteTarget && resolvedCanDelete)} onClose={() => setDeleteTarget(null)}>
        <DialogTitle>Confirmar eliminación</DialogTitle>
        <DialogContent>
          <Typography variant="body2">Esta acción eliminará el registro seleccionado.</Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDeleteTarget(null)}>Cancelar</Button>
          <Button color="error" onClick={handleDelete}>
            Eliminar
          </Button>
        </DialogActions>
      </Dialog>
    </>
  );
}

CrudResourceModule.propTypes = {
  title: PropTypes.string.isRequired,
  path: PropTypes.string.isRequired,
  columns: PropTypes.array.isRequired,
  fields: PropTypes.oneOfType([PropTypes.array, PropTypes.func]).isRequired,
  defaultOrdering: PropTypes.string,
  extraFilters: PropTypes.array,
  mapPayload: PropTypes.func,
  onView: PropTypes.func,
  searchPlaceholder: PropTypes.string,
  canCreate: PropTypes.bool,
  canEdit: PropTypes.bool,
  canDelete: PropTypes.bool
};
