import PropTypes from 'prop-types';

import Button from '@mui/material/Button';
import IconButton from '@mui/material/IconButton';
import MenuItem from '@mui/material/MenuItem';
import Pagination from '@mui/material/Pagination';
import Paper from '@mui/material/Paper';
import Stack from '@mui/material/Stack';
import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell from '@mui/material/TableCell';
import TableContainer from '@mui/material/TableContainer';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';

import DeleteOutlined from '@ant-design/icons/DeleteOutlined';
import EditOutlined from '@ant-design/icons/EditOutlined';
import EyeOutlined from '@ant-design/icons/EyeOutlined';
import PlusOutlined from '@ant-design/icons/PlusOutlined';

import MainCard from 'components/MainCard';
import { EmptyState, ErrorState, LoadingState } from 'components/common/PageFeedback';

export default function ResourceTableCard({
  title,
  rows,
  columns,
  loading,
  error,
  searchValue,
  searchPlaceholder = 'Buscar...',
  onSearchChange,
  onCreate,
  onEdit,
  onDelete,
  onView,
  pagination,
  onPageChange,
  extraFilters = [],
  filters = {},
  onFilterChange
}) {
  return (
    <MainCard
      content={false}
      boxShadow
      sx={{
        overflow: 'hidden'
      }}
    >
      <Stack
        direction={{ xs: 'column', md: 'row' }}
        sx={{
          px: 3,
          py: 2.25,
          gap: 1.5,
          justifyContent: 'space-between',
          alignItems: { md: 'center' },
          borderBottom: '1px solid',
          borderColor: 'divider'
        }}
      >
        <Stack sx={{ gap: 0.25 }}>
          <Typography variant="h4">{title}</Typography>
          <Typography variant="caption" color="text.secondary">
            {pagination.total || 0} registros
          </Typography>
        </Stack>
        <Stack direction={{ xs: 'column', sm: 'row' }} sx={{ gap: 1 }}>
          <TextField
            size="small"
            placeholder={searchPlaceholder}
            value={searchValue}
            onChange={(event) => onSearchChange(event.target.value)}
            sx={{ minWidth: { sm: 260 } }}
          />
          {extraFilters.map((filter) => (
            <TextField
              key={filter.key}
              select
              size="small"
              label={filter.label}
              value={filters[filter.key] || ''}
              onChange={(event) => onFilterChange(filter.key, event.target.value)}
              sx={{ minWidth: 160 }}
            >
              <MenuItem value="">Todos</MenuItem>
              {filter.options.map((option) => (
                <MenuItem key={option.value} value={option.value}>
                  {option.label}
                </MenuItem>
              ))}
            </TextField>
          ))}
          {onCreate ? (
            <Button startIcon={<PlusOutlined />} onClick={onCreate} variant="contained">
              Nuevo
            </Button>
          ) : null}
        </Stack>
      </Stack>

      {error ? <ErrorState message={error} /> : null}
      {loading ? <LoadingState /> : null}

      {!loading && rows.length === 0 ? (
        <EmptyState message="No encontramos resultados con los filtros actuales." />
      ) : (
        <TableContainer component={Paper} sx={{ borderRadius: 0, boxShadow: 'none', border: 'none' }}>
          <Table size="small" stickyHeader>
            <TableHead>
              <TableRow>
                {columns.map((column) => (
                  <TableCell key={column.key}>{column.label}</TableCell>
                ))}
                <TableCell align="right">Acciones</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {rows.map((row) => (
                <TableRow
                  key={row.id}
                  hover
                  sx={{
                    transition: 'background-color 0.2s ease',
                    '&:last-of-type td': { borderBottom: 'none' }
                  }}
                >
                  {columns.map((column) => (
                    <TableCell key={`${row.id}-${column.key}`}>{column.render ? column.render(row) : row[column.key] || '-'}</TableCell>
                  ))}
                  <TableCell align="right">
                    {onView ? (
                      <IconButton onClick={() => onView(row)} size="small">
                        <EyeOutlined />
                      </IconButton>
                    ) : null}
                    {onEdit ? (
                      <IconButton onClick={() => onEdit(row)} size="small">
                        <EditOutlined />
                      </IconButton>
                    ) : null}
                    {onDelete ? (
                      <IconButton color="error" onClick={() => onDelete(row)} size="small">
                        <DeleteOutlined />
                      </IconButton>
                    ) : null}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <Stack sx={{ px: 3, py: 2, alignItems: { xs: 'center', md: 'flex-end' }, borderTop: '1px solid', borderColor: 'divider' }}>
        <Pagination
          count={Math.max(1, Math.ceil((pagination.total || 1) / (pagination.pageSize || 10)))}
          page={pagination.page}
          onChange={(_, page) => onPageChange(page)}
          color="primary"
        />
      </Stack>
    </MainCard>
  );
}

ResourceTableCard.propTypes = {
  title: PropTypes.string.isRequired,
  rows: PropTypes.array.isRequired,
  columns: PropTypes.array.isRequired,
  loading: PropTypes.bool.isRequired,
  error: PropTypes.string,
  searchValue: PropTypes.string.isRequired,
  searchPlaceholder: PropTypes.string,
  onSearchChange: PropTypes.func.isRequired,
  onCreate: PropTypes.func,
  onEdit: PropTypes.func,
  onDelete: PropTypes.func,
  onView: PropTypes.func,
  pagination: PropTypes.shape({
    page: PropTypes.number,
    pageSize: PropTypes.number,
    total: PropTypes.number
  }).isRequired,
  onPageChange: PropTypes.func.isRequired,
  extraFilters: PropTypes.array,
  filters: PropTypes.object,
  onFilterChange: PropTypes.func
};
