import { useCallback, useEffect, useMemo, useState } from 'react';

import { listResource } from 'lib/http/resourceClient';

export default function usePaginatedResource(path, initialParams = {}) {
  const [items, setItems] = useState([]);
  const [count, setCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [params, setParams] = useState({
    page: 1,
    page_size: 10,
    search: '',
    ordering: '',
    ...initialParams
  });

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const data = await listResource(path, params);
      if (Array.isArray(data)) {
        setItems(data);
        setCount(data.length);
      } else {
        setItems(data.results || []);
        setCount(data.count || 0);
      }
    } catch (err) {
      setError(err?.response?.data?.detail || 'No se pudo cargar la información.');
    } finally {
      setLoading(false);
    }
  }, [params, path]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const pagination = useMemo(
    () => ({
      page: Number(params.page) || 1,
      pageSize: Number(params.page_size) || 10,
      total: count
    }),
    [count, params.page, params.page_size]
  );

  return {
    items,
    count,
    loading,
    error,
    params,
    setParams,
    pagination,
    refetch: fetchData
  };
}

