import PropTypes from 'prop-types';
import { useMemo } from 'react';

import Button from '@mui/material/Button';
import Checkbox from '@mui/material/Checkbox';
import Dialog from '@mui/material/Dialog';
import DialogActions from '@mui/material/DialogActions';
import DialogContent from '@mui/material/DialogContent';
import DialogTitle from '@mui/material/DialogTitle';
import FormControlLabel from '@mui/material/FormControlLabel';
import Grid from '@mui/material/Grid';
import MenuItem from '@mui/material/MenuItem';
import TextField from '@mui/material/TextField';

import { Formik } from 'formik';
import * as Yup from 'yup';

function normalizeInitialValues(fields, initialData) {
  const values = {};
  fields.forEach((field) => {
    const value = initialData?.[field.name];
    if (value !== undefined && value !== null) {
      if (field.type === 'date' && typeof value === 'string') {
        values[field.name] = value.slice(0, 10);
      } else if (field.type === 'datetime-local' && typeof value === 'string') {
        values[field.name] = value.slice(0, 16);
      } else {
        values[field.name] = value;
      }
    } else if (field.type === 'checkbox') {
      values[field.name] = field.defaultValue ?? false;
    } else {
      values[field.name] = field.defaultValue ?? '';
    }
  });
  return values;
}

function buildValidationSchema(fields) {
  const shape = {};
  fields.forEach((field) => {
    let validator = Yup.mixed();
    if (field.type === 'email') validator = Yup.string().email('Correo inválido');
    if (field.type === 'number') {
      validator = Yup.number()
        .transform((value, originalValue) => (originalValue === '' ? null : value))
        .nullable()
        .typeError('Debe ser numérico');
    }
    if (field.type === 'checkbox') validator = Yup.boolean();
    if (!['number', 'checkbox'].includes(field.type)) validator = validator.concat(Yup.string());
    if (field.required) validator = validator.required('Campo requerido');
    shape[field.name] = validator;
  });
  return Yup.object().shape(shape);
}

export default function ResourceFormDialog({ open, title, fields, initialData, onClose, onSubmit }) {
  const initialValues = useMemo(() => normalizeInitialValues(fields, initialData), [fields, initialData]);
  const validationSchema = useMemo(() => buildValidationSchema(fields), [fields]);

  return (
    <Dialog open={open} onClose={onClose} fullWidth maxWidth="md">
      <DialogTitle>{title}</DialogTitle>
      <Formik enableReinitialize initialValues={initialValues} validationSchema={validationSchema} onSubmit={onSubmit}>
        {({ values, errors, touched, handleChange, handleBlur, handleSubmit, isSubmitting, setFieldValue }) => (
          <form onSubmit={handleSubmit}>
            <DialogContent dividers>
              <Grid container spacing={2}>
                {fields.map((field) => (
                  <Grid key={field.name} size={{ xs: 12, md: field.fullWidth ? 12 : 6 }}>
                    {field.type === 'checkbox' ? (
                      <FormControlLabel
                        control={<Checkbox checked={Boolean(values[field.name])} onChange={(event) => setFieldValue(field.name, event.target.checked)} />}
                        label={field.label}
                      />
                    ) : (
                      <TextField
                        fullWidth
                        select={field.type === 'select'}
                        multiline={field.type === 'textarea'}
                        rows={field.type === 'textarea' ? 3 : undefined}
                        type={field.type === 'textarea' || field.type === 'select' ? 'text' : field.type}
                        label={field.label}
                        name={field.name}
                        value={values[field.name]}
                        onChange={handleChange}
                        onBlur={handleBlur}
                        required={field.required}
                        error={Boolean(touched[field.name] && errors[field.name])}
                        helperText={touched[field.name] && errors[field.name] ? errors[field.name] : field.helperText || ''}
                        InputLabelProps={field.type === 'date' || field.type === 'datetime-local' ? { shrink: true } : undefined}
                      >
                        {field.type === 'select'
                          ? (field.options || []).map((option) => (
                              <MenuItem key={option.value} value={option.value}>
                                {option.label}
                              </MenuItem>
                            ))
                          : null}
                      </TextField>
                    )}
                  </Grid>
                ))}
              </Grid>
            </DialogContent>
            <DialogActions>
              <Button onClick={onClose} color="secondary">
                Cancelar
              </Button>
              <Button type="submit" variant="contained" disabled={isSubmitting}>
                Guardar
              </Button>
            </DialogActions>
          </form>
        )}
      </Formik>
    </Dialog>
  );
}

ResourceFormDialog.propTypes = {
  open: PropTypes.bool.isRequired,
  title: PropTypes.string.isRequired,
  fields: PropTypes.array.isRequired,
  initialData: PropTypes.object,
  onClose: PropTypes.func.isRequired,
  onSubmit: PropTypes.func.isRequired
};
